Here are the public test cases for feature3_1_serialize_arrays:
{
  "description": "Serialize arrays as XML array elements, preserving element order and using a compact self-closing element for an empty array.",
  "cases": [
    {
      "input": {
        "operation": "serialize_fragment",
        "value": {
          "kind": "array",
          "items": [
            {
              "kind": "integer",
              "value": 1
            },
            {
              "kind": "integer",
              "value": 2
            },
            {
              "kind": "integer",
              "value": 3
            }
          ]
        }
      },
      "expected_output": "<array>\n\t<integer>1</integer>\n\t<integer>2</integer>\n\t<integer>3</integer>\n</array>\n"
    },
    {
      "input": {
        "operation": "serialize_fragment",
        "value": {
          "kind": "array",
          "items": []
        }
      },
      "expected_output": "<array/>\n"
    }
  ]
}

Here are the public test cases for feature3_2_serialize_dictionaries:
{
  "description": "Serialize dictionaries as XML dict elements, sorting keys by their textual form and using a compact self-closing element for an empty dictionary.",
  "cases": [
    {
      "input": {
        "operation": "serialize_fragment",
        "value": {
          "kind": "object",
          "entries": [
            {
              "key": {
                "kind": "symbol_text",
                "value": "foo"
              },
              "value": {
                "kind": "symbol_text",
                "value": "bar"
              }
            },
            {
              "key": {
                "kind": "symbol_text",
                "value": "abc"
              },
              "value": {
                "kind": "integer",
                "value": 123
              }
            }
          ]
        }
      },
      "expected_output": "<dict>\n\t<key>abc</key>\n\t<integer>123</integer>\n\t<key>foo</key>\n\t<string>bar</string>\n</dict>\n"
    },
    {
      "input": {
        "operation": "serialize_fragment",
        "value": {
          "kind": "object",
          "entries": []
        }
      },
      "expected_output": "<dict/>\n"
    }
  ]
}

Here are the public test cases for feature3_3_serialize_nested_collections:
{
  "description": "Serialize nested arrays and dictionaries recursively while preserving the expected XML tree shape and indentation.",
  "cases": [
    {
      "input": {
        "operation": "serialize_fragment",
        "value": {
          "kind": "object",
          "entries": [
            {
              "key": {
                "kind": "symbol_text",
                "value": "ary"
              },
              "value": {
                "kind": "array",
                "items": [
                  {
                    "kind": "integer",
                    "value": 1
                  },
                  {
                    "kind": "symbol_text",
                    "value": "b"
                  },
                  {
                    "kind": "string",
                    "value": "3"
                  }
                ]
              }
            }
          ]
        }
      },
      "expected_output": "<dict>\n\t<key>ary</key>\n\t<array>\n\t\t<integer>1</integer>\n\t\t<string>b</string>\n\t\t<string>3</string>\n\t</array>\n</dict>\n"
    },
    {
      "input": {
        "operation": "serialize_fragment",
        "value": {
          "kind": "array",
          "items": [
            {
              "kind": "object",
              "entries": [
                {
                  "key": {
                    "kind": "symbol_text",
                    "value": "foo"
                  },
                  "value": {
                    "kind": "string",
                    "value": "bar"
                  }
                }
              ]
            },
            {
              "kind": "symbol_text",
              "value": "b"
            },
            {
              "kind": "integer",
              "value": 3
            }
          ]
        }
      },
      "expected_output": "<array>\n\t<dict>\n\t\t<key>foo</key>\n\t\t<string>bar</string>\n\t</dict>\n\t<string>b</string>\n\t<integer>3</integer>\n</array>\n"
    }
  ]
}

